import React, { useState, useRef } from 'react';
import { Inbox, Send, Trash2, Edit, Search, Star, X, Paperclip } from 'lucide-react';
import './css/Messaging.css';
import axios from '../axios';

const Messaging = ({ userId }) => {
    const [activeCategory, setActiveCategory] = useState('inbox');
    const [messages, setMessages] = useState([
        { id: 1, from: 'John Doe', subject: 'Hello!', content: 'Hi there, how are you?', date: '2023-05-01', read: false, starred: false },
        { id: 2, from: 'Jane Smith', subject: 'Meeting tomorrow', content: 'Don\'t forget about our meeting tomorrow at 2 PM.', date: '2023-04-30', read: true, starred: true },
        { id: 3, from: 'Alice Johnson', subject: 'Project update', content: 'I\'ve finished the first draft of the project. Please review when you have a chance.', date: '2023-04-29', read: true, starred: false },
    ]);
    const [selectedMessage, setSelectedMessage] = useState(null);
    const [searchTerm, setSearchTerm] = useState('');
    const [showNewMessageModal, setShowNewMessageModal] = useState(false);
    const [newMessage, setNewMessage] = useState({ to: '', subject: '', content: '', attachment: null });
    const fileInputRef = useRef(null);

    const filteredMessages = messages.filter(message => 
        message.from.toLowerCase().includes(searchTerm.toLowerCase()) ||
        message.subject.toLowerCase().includes(searchTerm.toLowerCase()) ||
        message.content.toLowerCase().includes(searchTerm.toLowerCase())
    );

    const renderMessageList = () => {
        return filteredMessages.map(message => (
            <div 
                key={message.id} 
                className={`message-item ${!message.read ? 'unread' : ''} ${message.starred ? 'starred' : ''} ${selectedMessage && selectedMessage.id === message.id ? 'selected' : ''}`}
                onClick={() => setSelectedMessage(message)}
            >
                <div className="message-item-content">
                    <div className="message-header">
                        <span className="message-from">{message.from}</span>
                        <span className="message-date">{message.date}</span>
                    </div>
                    <div className="message-subject">{message.subject}</div>
                    <div className="message-preview">{message.content}</div>
                </div>
                <button className="star-btn" onClick={(e) => {
                    e.stopPropagation();
                    setMessages(messages.map(m => m.id === message.id ? {...m, starred: !m.starred} : m));
                }}>
                    <Star size={16} className={message.starred ? 'starred' : ''} />
                </button>
            </div>
        ));
    };

    const renderMessageDetail = () => {
        if (!selectedMessage) return null;
        return (
            <div className="message-detail">
                <h3>{selectedMessage.subject}</h3>
                <div className="message-info">
                    <span>From: {selectedMessage.from}</span>
                    <span>Date: {selectedMessage.date}</span>
                </div>
                <div className="message-content">{selectedMessage.content}</div>
                <button className="reply-btn" onClick={() => {/* Implement reply functionality */}}>
                    Reply
                </button>
            </div>
        );
    };

    const handleNewMessage = () => {
        setShowNewMessageModal(true);
    };

    const closeNewMessageModal = () => {
        setShowNewMessageModal(false);
        setNewMessage({ to: '', subject: '', content: '', attachment: null });
    };

    const handleNewMessageChange = (e) => {
        const { name, value } = e.target;
        setNewMessage(prev => ({ ...prev, [name]: value }));
    };

    const handleFileChange = (e) => {
        const file = e.target.files[0];
        if (file) {
            setNewMessage(prev => ({ ...prev, attachment: file }));
        }
    };

    const triggerFileInput = () => {
        fileInputRef.current.click();
    };

    const sendNewMessage = async () => {
        try {
            const response = await axios.post('/api/messages', {
                recipient: newMessage.to,
                content: newMessage.content,
                attachment: newMessage.attachment ? newMessage.attachment.name : null
            });

            const sentMessage = {
                id: response.data._id,
                from: 'You',
                to: newMessage.to,
                subject: newMessage.subject,
                content: newMessage.content,
                date: new Date().toISOString().split('T')[0],
                read: true,
                starred: false,
                attachment: newMessage.attachment ? newMessage.attachment.name : null
            };

            setMessages([sentMessage, ...messages]);
            closeNewMessageModal();
        } catch (error) {
            console.error('Error sending message:', error);
            // You might want to show an error message to the user here
        }
    };

    const renderNewMessageModal = () => {
        if (!showNewMessageModal) return null;
        return (
            <div className="new-message-modal">
                <div className="new-message-content">
                    <div className="new-message-header">
                        <h3>New Message</h3>
                        <button onClick={closeNewMessageModal} className="close-btn">
                            <X size={18} />
                        </button>
                    </div>
                    <div className="new-message-form">
                        <input
                            type="text"
                            name="to"
                            placeholder="To"
                            value={newMessage.to}
                            onChange={handleNewMessageChange}
                        />
                        <input
                            type="text"
                            name="subject"
                            placeholder="Subject"
                            value={newMessage.subject}
                            onChange={handleNewMessageChange}
                        />
                        <textarea
                            name="content"
                            placeholder="Message"
                            value={newMessage.content}
                            onChange={handleNewMessageChange}
                        />
                        <div className="attachment-section">
                            <button onClick={triggerFileInput} className="attachment-btn">
                                <Paperclip size={18} />
                                Attach File
                            </button>
                            <input
                                type="file"
                                ref={fileInputRef}
                                onChange={handleFileChange}
                                style={{ display: 'none' }}
                            />
                            {newMessage.attachment && (
                                <span className="attachment-name">{newMessage.attachment.name}</span>
                            )}
                        </div>
                        <button onClick={sendNewMessage} className="send-btn">Send</button>
                    </div>
                </div>
            </div>
        );
    };

    return (
        <div className="messaging-container">
            <div className="messaging-sidebar">
                <button className="new-message-btn" onClick={handleNewMessage}>
                    <Edit size={18} />
                    New Message
                </button>
                <div className="message-categories">
                    <button
                        className={`category-btn ${activeCategory === 'inbox' ? 'active' : ''}`}
                        onClick={() => setActiveCategory('inbox')}
                    >
                        <Inbox size={18} />
                        Inbox
                    </button>
                    <button
                        className={`category-btn ${activeCategory === 'sent' ? 'active' : ''}`}
                        onClick={() => setActiveCategory('sent')}
                    >
                        <Send size={18} />
                        Sent
                    </button>
                    <button
                        className={`category-btn ${activeCategory === 'trash' ? 'active' : ''}`}
                        onClick={() => setActiveCategory('trash')}
                    >
                        <Trash2 size={18} />
                        Trash
                    </button>
                </div>
            </div>
            <div className="messaging-content">
                <div className="messaging-header">
                    <h2>{activeCategory.charAt(0).toUpperCase() + activeCategory.slice(1)}</h2>
                    <div className="search-bar">
                        <input 
                            type="text" 
                            placeholder="Search messages..." 
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                        />
                        <Search size={18} />
                    </div>
                </div>
                <div className="message-list-container">
                    <div className="message-list">
                        {renderMessageList()}
                    </div>
                    <div className="message-detail-container">
                        {renderMessageDetail()}
                    </div>
                </div>
            </div>
            {renderNewMessageModal()}
        </div>
    );
};

export default Messaging;
